import pandas as pdimport numpy as npimport seaborn as snsimport matplotlib.pyplot as plt# --- LOAD DATA ----------------------------------------------------------------trainings = pd.read_csv("data/processed/running_clean.csv")# --- PLOT SETTINGS ------------------------------------------------------------# Color palettePRIMARY   = "#30D158"SECONDARY = "#34C759"ACCENT    = "#FF375F"sns.set_theme(style="whitegrid")plt.style.use('seaborn-v0_8-whitegrid')# --- TRAINING VOLUME ----------------------------------------------------------# Sessions per yearsessions_per_year = trainings.groupby('year').size().reset_index(name='sessions')plt.figure(figsize=(10, 5))sns.barplot(data=sessions_per_year, x='year', y='sessions', color=PRIMARY)plt.title('Running Sessions per Year', fontsize=14)plt.xlabel('Year')plt.ylabel('Number of Sessions')plt.tight_layout()plt.show()# Total kilometers per yearkilometers_per_year = trainings.groupby('year')['distance_km'].sum().reset_index(name='kilometers')plt.figure(figsize=(10, 5))sns.barplot(data=kilometers_per_year, x='year', y='kilometers', color=PRIMARY)plt.title('Total Kilometers per Year', fontsize=14)plt.xlabel('Year')plt.ylabel('Kilometers')plt.tight_layout()plt.show()# Create pivot table (year vs month)heatmap_data = trainings.groupby(['year', 'month']).size().reset_index(name='sessions')heatmap_pivot = heatmap_data.pivot(index='year', columns='month', values='sessions').fillna(0)# Reorder months chronologicallymonth_order = ['January', 'February', 'March', 'April', 'May', 'June',               'July', 'August', 'September', 'October', 'November', 'December']heatmap_pivot = heatmap_pivot.reindex(columns=month_order)# Plot heatmapplt.figure(figsize=(14, 6))sns.heatmap(heatmap_pivot, cmap='Greens', linewidths=0.5,            annot=True, fmt='.0f', cbar_kws={'label': 'Sessions'})plt.title('Training Sessions Heatmap (Year vs Month)', fontsize=14)plt.xlabel('Month')plt.ylabel('Year')plt.tight_layout()plt.show()# --- PERFORMANCE --------------------------------------------------------------# Pace distribution per yearplt.figure(figsize=(10, 5))sns.boxplot(data=trainings, x='year', y='pace_min_km', color=PRIMARY)plt.title('Pace per Year', fontsize=14)plt.xlabel('Year')plt.ylabel('Pace (min/km)')plt.tight_layout()plt.show()# Relationship between distance and paceplt.figure(figsize=(10, 5))sns.scatterplot(data=trainings, x='distance_km', y='pace_min_km', hue='year', palette='tab10')plt.title('Distance vs Pace', fontsize=14)plt.xlabel('Distance (km)')plt.ylabel('Pace (min/km)')plt.tight_layout()plt.show()# --- TRAINING PATTERNS --------------------------------------------------------# Sessions per weekdaysessions_per_weekday = trainings.groupby('day_of_week').size().reset_index(name='sessions')# Reorder weekdays chronologicallyweekday_order = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday']plt.figure(figsize=(10, 5))sns.barplot(data=sessions_per_weekday, x='day_of_week', y='sessions', color=PRIMARY, order=weekday_order)plt.title('Running Sessions per Weekday', fontsize=14)plt.xlabel('Weekday')plt.ylabel('Number of Sessions')plt.tight_layout()plt.show()# Sessions per time of daysessions_per_daytime = trainings.groupby('time_of_day').size().reset_index(name='sessions')# Reorder time of day chronologicallydaytime_order = ['morning', 'afternoon', 'evening']plt.figure(figsize=(10, 5))sns.barplot(data=sessions_per_daytime, x='time_of_day', y='sessions', color=PRIMARY, order=daytime_order)plt.title('Running Sessions per Time of Day', fontsize=14)plt.xlabel('Time of Day')plt.ylabel('Number of Sessions')plt.tight_layout()plt.show()# --- XXXXXXXXXXXXXXXXX --------------------------------------------------------